+// HealthCheckHandler handles health endpoint
+func (s *Server) HealthCheckHandler(c *gin.Context) {
+	c.JSON(http.StatusOK, gin.H{
+		"status":  "ok",
+		"service": "PicoD",
+		"version": "0.0.1",
+		"uptime":  time.Since(s.startTime).String(),
+	})
+}

