	endTime := time.Now()

	response := ExecuteResponse{
		Stdout:    stdout.String(),
		Stderr:    stderr.String(),
		StartTime: startTime,
		EndTime:   endTime,
		Duration:  endTime.Sub(startTime).Seconds(),
	}

	if ctx.Err() == context.DeadlineExceeded {
		response.ExitCode = TimeoutExitCode
		response.Stderr = fmt.Sprintf("Command timed out after %d seconds", int(timeout.Seconds()))
	} else if err != nil {
		if exitError, ok := err.(*exec.ExitError); ok {
			response.ExitCode = exitError.ExitCode()
		} else {
			response.ExitCode = 1
		}
	}

	c.JSON(http.StatusOK, response)
}

// UploadFileHandler handles file upload (JSON or multipart)
func (s *Server) UploadFileHandler(c *gin.Context) {
	contentType := c.GetHeader("Content-Type")

	if strings.HasPrefix(contentType, "multipart/form-data") {
		s.handleMultipartUpload(c)
	} else {
		s.handleJSONUpload(c)
	}
}

func (s *Server) handleMultipartUpload(c *gin.Context) {
	filePath := c.PostForm("path")
	if filePath == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  http.StatusBadRequest,
		})
		return
	}

	fileHeader, err := c.FormFile("file")
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "file is required",
			"code":  http.StatusBadRequest,
		})
		return
	}

	safePath, err := s.sanitizePath(filePath)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Invalid path: %v", err),
			"code":  http.StatusBadRequest,
		})
		return
	}

	// Create parent directories
	parentDir := filepath.Dir(safePath)
	if err := os.MkdirAll(parentDir, 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("Failed to create directories: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	// Save file
	src, err := fileHeader.Open()
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("Failed to open file: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}
	defer src.Close()

	dst, err := os.Create(safePath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("Failed to create file: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, src); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("Failed to write file: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	// Set file mode
	modeStr := c.PostForm("mode")
	if modeStr != "" {
		mode := s.parseFileMode(modeStr)
		os.Chmod(safePath, mode)
	} else {
		os.Chmod(safePath, 0644)
	}

	info, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     filePath,
		Size:     info.Size(),
		Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
		Modified: info.ModTime(),
	})
}

func (s *Server) handleJSONUpload(c *gin.Context) {
	var req UploadFileRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": err.Error(),
			"code":  http.StatusBadRequest,
		})
		return
	}

	safePath, err := s.sanitizePath(req.Path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Invalid path: %v", err),
			"code":  http.StatusBadRequest,
		})
		return
	}

	// Decode base64 content
	content, err := base64.StdEncoding.DecodeString(req.Content)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("invalid base64: %v", err),
			"code":  http.StatusBadRequest,
		})
		return
	}

	// Create parent directories
	parentDir := filepath.Dir(safePath)
	if err := os.MkdirAll(parentDir, 0755); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("Failed to create directories: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	// Write file
	mode := s.parseFileMode(req.Mode)
	if err := os.WriteFile(safePath, content, mode); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": fmt.Sprintf("Failed to write file: %v", err),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	info, _ := os.Stat(safePath)
	c.JSON(http.StatusOK, FileInfo{
		Path:     req.Path,
		Size:     info.Size(),
		Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
		Modified: info.ModTime(),
	})
}

func (s *Server) parseFileMode(modeStr string) os.FileMode {
	if modeStr == "" {
		return 0644
	}
	mode, err := strconv.ParseUint(modeStr, 8, 32)
	if err != nil || mode > maxFileMode {
		return 0644
	}
	return os.FileMode(mode)
}

func (s *Server) sanitizePath(p string) (string, error) {
	// Clean and resolve the path
	cleaned := filepath.Clean(p)
	if strings.HasPrefix(cleaned, "..") || strings.Contains(cleaned, "../") || strings.Contains(cleaned, "..\\") {
		return "", fmt.Errorf("path escapes workspace")
	}

	absPath := filepath.Join(s.workspaceDir, cleaned)
	if !strings.HasPrefix(absPath, s.workspaceDir) {
		return "", fmt.Errorf("path escapes workspace")
	}

	return absPath, nil
}

// ListFilesHandler handles file listing
func (s *Server) ListFilesHandler(c *gin.Context) {
	path := c.Query("path")
	if path == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Missing 'path' query parameter",
			"code":  http.StatusBadRequest,
		})
		return
	}

	safePath, err := s.sanitizePath(path)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Invalid path: %v", err),
			"code":  http.StatusBadRequest,
		})
		return
	}

	// Check if directory exists
	info, err := os.Stat(safePath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "Directory not found",
				"code":  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": err.Error(),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	if !info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Path is not a directory",
			"code":  http.StatusBadRequest,
		})
		return
	}

	entries, err := os.ReadDir(safePath)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": err.Error(),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	files := make([]FileEntry, 0, len(entries))
	for _, entry := range entries {
		info, err := entry.Info()
		if err != nil {
			continue // Skip entries where Info() fails
		}

		files = append(files, FileEntry{
			Name:     entry.Name(),
			Size:     info.Size(),
			Modified: info.ModTime(),
			Mode:     fmt.Sprintf("%04o", info.Mode().Perm()),
			IsDir:    entry.IsDir(),
		})
	}

	c.JSON(http.StatusOK, ListFilesResponse{Files: files})
}

// DownloadFileHandler handles file download
func (s *Server) DownloadFileHandler(c *gin.Context) {
	pathParam := c.Param("path")
	if pathParam == "" {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "path is required",
			"code":  http.StatusBadRequest,
		})
		return
	}

	safePath, err := s.sanitizePath(pathParam)
	if err != nil {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": fmt.Sprintf("Invalid path: %v", err),
			"code":  http.StatusBadRequest,
		})
		return
	}

	info, err := os.Stat(safePath)
	if err != nil {
		if os.IsNotExist(err) {
			c.JSON(http.StatusNotFound, gin.H{
				"error": "File not found",
				"code":  http.StatusNotFound,
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{
			"error": err.Error(),
			"code":  http.StatusInternalServerError,
		})
		return
	}

	if info.IsDir() {
		c.JSON(http.StatusBadRequest, gin.H{
			"error": "Path is a directory, not a file",
			"code":  http.StatusBadRequest,
		})
		return
	}

	// Set download headers
	c.Header("Content-Description", "File Transfer")
	c.Header("Content-Transfer-Encoding", "binary")
	filename := filepath.Base(safePath)
	c.Header("Content-Disposition", fmt.Sprintf("attachment; filename=\"%s\"", filename))

	contentType := mime.TypeByExtension(filepath.Ext(safePath))
	if contentType == "" {
		contentType = "application/octet-stream"
	}
	c.Header("Content-Type", contentType)

	c.File(safePath)
}

// HealthCheckHandler handles health endpoint
func (s *Server) HealthCheckHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "PicoD",
		"version": "0.0.1",
		"uptime":  time.Since(s.startTime).String(),
	})
}

